const onReady=e=>{"loading"===document.readyState?document.addEventListener("DOMContentLoaded",e):e()},revealElements=()=>{const e=document.querySelectorAll(".reveal");e.length&&window.requestAnimationFrame(()=>{e.forEach((e,t)=>{setTimeout(()=>{e.classList.add("show")},100*t)})})},initSmoothScroll=()=>{document.querySelectorAll('a[href^="#"]').forEach(e=>{const t=e.getAttribute("href");t&&"#"!==t&&e.addEventListener("click",e=>{try{const o=document.querySelector(t);o&&(e.preventDefault(),o.scrollIntoView({behavior:"smooth",block:"start"}))}catch(e){console.warn("Smooth scroll failed for:",t,e)}})})},initFaqToggle=()=>{const e=document.querySelectorAll(".faq-toggle");e.length&&e.forEach(e=>{e.addEventListener("click",()=>{const t=e.closest(".faq-item");if(!t)return;const o=t.classList.toggle("open");e.setAttribute("aria-expanded",String(o)),document.querySelectorAll(".faq-item.open").forEach(e=>{if(e!==t){e.classList.remove("open");const t=e.querySelector(".faq-toggle");t&&t.setAttribute("aria-expanded","false")}})})})};onReady(()=>{revealElements(),initSmoothScroll(),initFaqToggle()});